import {Header as HeaderDS, Text, Box} from '@semparar/design-system-app';
import React from 'react';
import {ScrollViewProps, ScrollView} from 'react-native';
import {getStatusBarHeight} from 'react-native-status-bar-height';
import styled from 'styled-components/native';

import theme from '../../../styles/theme';

interface ContainerProps {
  bgColor: string;
}

export const ScrollViewContainer = styled(
  ScrollView as new (props: ScrollViewProps) => ScrollView,
).attrs(props => {
  return {
    contentContainerStyle: {
      flexGrow: 1,
      backgroundColor: props.bgColor || '#F4F7F7',
    },
    style: {
      backgroundColor: props.bgColor || '#F4F7F7',
    },
    ...props,
  } as ScrollViewProps;
})``;

export const Container = styled.View<ContainerProps>`
  margin-top: ${getStatusBarHeight(true)};
  flex-grow: 1;
  background-color: ${props => props.bgColor};
`;

export const Header = styled(({...rest}: HeaderDS['props']) => (
  <HeaderDS {...rest} />
)).attrs(() => {
  return {
    isHome: false,
  } as HeaderDS['props'];
})``;

export const ContainerHeader = styled(Box).attrs(() => {
  return {
    bgColor: theme.colors.LIGHT_BASE_01,
    justify: 'flex-end',
  } as Box['props'];
})``;

export const Title = styled(
  ({...rest}: Omit<Text['props'], 'type' | 'mt' | 'ml'>) => <Text {...rest} />,
).attrs(({color}) => {
  return {
    type: 'paragraphXXL',
    color: color || theme.colors.PRYMARY_BASE_01,
    mt: 'xxs',
    ml: 'smaller',
    index: 1,
  } as Text['props'];
})``;

